import{_ as e,o as a,c as t,ai as l}from"./chunks/framework.CmIi9huC.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"title":"Introduction","outline":"deep"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function r(s,i,o,h,d,u){return a(),t("div",null,[...i[0]||(i[0]=[l('<h1 id="authkit" tabindex="-1">AuthKit <a class="header-anchor" href="#authkit" aria-label="Permalink to “AuthKit”">​</a></h1><p>AuthKit is a <strong>reusable, configuration-driven authentication system for Laravel</strong> that gives you complete control over authentication flows, UI, and behavior — without locking you into rigid scaffolding.</p><p>It is designed for developers who want <strong>speed, flexibility, and long-term maintainability</strong> when building authentication into real applications.</p><h2 id="why-authkit" tabindex="-1">Why AuthKit? <a class="header-anchor" href="#why-authkit" aria-label="Permalink to “Why AuthKit?”">​</a></h2><p>Most authentication solutions fall into two extremes:</p><ul><li><strong>Too rigid</strong> — difficult to customize beyond basic use cases</li><li><strong>Too low-level</strong> — requiring you to build everything from scratch</li></ul><p>AuthKit sits in the middle.</p><p>It provides a <strong>complete authentication system out of the box</strong>, while still allowing you to <strong>customize and extend every part of the flow</strong>.</p><h2 id="what-you-get" tabindex="-1">What You Get <a class="header-anchor" href="#what-you-get" aria-label="Permalink to “What You Get”">​</a></h2><p>AuthKit ships with a full set of authentication and security features:</p><h3 id="core-authentication" tabindex="-1">Core Authentication <a class="header-anchor" href="#core-authentication" aria-label="Permalink to “Core Authentication”">​</a></h3><ul><li>User registration</li><li>Login and logout</li><li>Password confirmation for sensitive actions</li></ul><h3 id="security-flows" tabindex="-1">Security Flows <a class="header-anchor" href="#security-flows" aria-label="Permalink to “Security Flows”">​</a></h3><ul><li>Email verification (link and token-based)</li><li>Password reset flows</li><li>Two-factor authentication (TOTP, recovery codes, extensible methods)</li></ul><h3 id="ui-and-frontend" tabindex="-1">UI and Frontend <a class="header-anchor" href="#ui-and-frontend" aria-label="Permalink to “UI and Frontend”">​</a></h3><ul><li>Blade-based UI system</li><li>Theme-ready CSS structure</li><li>JavaScript runtime for enhanced form handling (AJAX support)</li></ul><h3 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to “Developer Experience”">​</a></h3><ul><li>Config-driven architecture</li><li>Action-based flow handling</li><li>DTO-based responses</li><li>Clean separation of concerns</li></ul><h3 id="extensibility" tabindex="-1">Extensibility <a class="header-anchor" href="#extensibility" aria-label="Permalink to “Extensibility”">​</a></h3><ul><li>Replace or extend actions</li><li>Custom mappers for persistence</li><li>Custom notifiers for delivery (email, SMS, etc.)</li><li>Flexible route and middleware configuration</li></ul><h2 id="designed-for-real-applications" tabindex="-1">Designed for Real Applications <a class="header-anchor" href="#designed-for-real-applications" aria-label="Permalink to “Designed for Real Applications”">​</a></h2><p>AuthKit is not just a starter template — it is built for production use.</p><p>It is especially suited for:</p><ul><li>SaaS platforms</li><li>Multi-tenant applications</li><li>Admin panels and dashboards</li><li>Products requiring customizable authentication flows</li><li>Teams that need long-term maintainability</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h2><ul><li>PHP 8.3 or higher</li><li>Laravel 12 or 13</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>Install AuthKit via Composer:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xul/auth-kit</span></span></code></pre></div><p>Publish configuration and resources:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Xul\\AuthKit\\AuthKitServiceProvider&quot;</span></span></code></pre></div><p>Run your migrations:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span></span></code></pre></div><p>Continue with the <a href="/auth-kit/quick-start.html">Quick Start</a> guide to get up and running.</p><h2 id="quick-example" tabindex="-1">Quick Example <a class="header-anchor" href="#quick-example" aria-label="Permalink to “Quick Example”">​</a></h2><p>Once installed, AuthKit provides ready-to-use authentication flows.</p><p>A typical setup includes:</p><ul><li>Configuring routes and middleware</li><li>Ensuring your user model supports required traits</li><li>Publishing and customizing views if needed</li></ul><p>From there, authentication flows such as registration, login, and two-factor authentication are immediately available.</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to “Core Concepts”">​</a></h2><p>Understanding these concepts will help you use AuthKit effectively:</p><h3 id="configuration-driven" tabindex="-1">Configuration-Driven <a class="header-anchor" href="#configuration-driven" aria-label="Permalink to “Configuration-Driven”">​</a></h3><p>Most behavior is controlled through configuration rather than hardcoded logic.</p><h3 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to “Actions”">​</a></h3><p>Each authentication flow is handled by dedicated action classes.</p><h3 id="dtos-data-transfer-objects" tabindex="-1">DTOs (Data Transfer Objects) <a class="header-anchor" href="#dtos-data-transfer-objects" aria-label="Permalink to “DTOs (Data Transfer Objects)”">​</a></h3><p>Actions return structured results that define:</p><ul><li>success state</li><li>errors</li><li>redirects</li><li>public payloads</li></ul><h3 id="support-layer" tabindex="-1">Support Layer <a class="header-anchor" href="#support-layer" aria-label="Permalink to “Support Layer”">​</a></h3><p>Handles complex flows such as:</p><ul><li>password resets</li><li>two-factor authentication</li><li>notification delivery</li><li>data mapping</li></ul><h3 id="ui-layer" tabindex="-1">UI Layer <a class="header-anchor" href="#ui-layer" aria-label="Permalink to “UI Layer”">​</a></h3><p>Blade views, CSS, and JavaScript work together to provide a flexible frontend system.</p><h2 id="documentation-overview" tabindex="-1">Documentation Overview <a class="header-anchor" href="#documentation-overview" aria-label="Permalink to “Documentation Overview”">​</a></h2><p>Start here:</p><ul><li><a href="/auth-kit/installation.html">Installation</a></li><li><a href="/auth-kit/quick-start.html">Quick Start</a></li><li><a href="/auth-kit/configuration.html">Configuration</a></li></ul><p>Explore features:</p><ul><li>Authentication flows</li><li>Security flows</li><li>UI customization</li></ul><p>Go deeper:</p><ul><li><a href="/auth-kit/extending/overview.html">Extending AuthKit</a></li><li><a href="/auth-kit/architecture/overview.html">Architecture Overview</a></li></ul><h2 id="extending-authkit" tabindex="-1">Extending AuthKit <a class="header-anchor" href="#extending-authkit" aria-label="Permalink to “Extending AuthKit”">​</a></h2><p>AuthKit is built to be extended.</p><p>You can:</p><ul><li>Replace default actions with your own</li><li>Customize how data is persisted using mappers</li><li>Change how notifications are delivered</li><li>Modify or replace UI components and flows</li></ul><p>See the <a href="/auth-kit/extending/overview.html">Extending AuthKit</a> section for details.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to “Contributing”">​</a></h2><p>Contributions are welcome.</p><p>If you want to improve AuthKit:</p><ul><li>Submit issues</li><li>Open pull requests</li><li>Suggest enhancements</li></ul><h2 id="support-and-feedback" tabindex="-1">Support and Feedback <a class="header-anchor" href="#support-and-feedback" aria-label="Permalink to “Support and Feedback”">​</a></h2><p>If you encounter issues or have ideas:</p><ul><li>Open an issue on GitHub</li><li>Provide clear reproduction steps when possible</li></ul><h2 id="star-the-repository" tabindex="-1">Star the Repository <a class="header-anchor" href="#star-the-repository" aria-label="Permalink to “Star the Repository”">​</a></h2><p>If AuthKit helps you build faster or cleaner authentication systems, consider starring the repository:</p><p>👉 <a href="https://github.com/Xultech-LTD/auth-kit" target="_blank" rel="noreferrer">https://github.com/Xultech-LTD/auth-kit</a></p><p>It helps others discover the project and supports continued development.</p><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to “Next Step”">​</a></h2><p>Proceed to the <a href="/auth-kit/installation.html">Installation</a> guide to begin integrating AuthKit into your application.</p>',78)])])}const f=e(n,[["render",r]]);export{p as __pageData,f as default};
